create table dirkspzm32.s_qs_babtec_adr_l (
    typ             varchar2(1 char) not null enable,
    nummer          varchar2(30 char) not null enable,
    bez1            varchar2(50 char),
    bez2            varchar2(50 char),
    bez3            varchar2(50 char),
    strasse         varchar2(50 char),
    land            varchar2(50 char),
    plz             varchar2(10 char),
    stadt           varchar2(50 char),
    ansprechpartner varchar2(50 char),
    telefon         varchar2(20 char),
    fax             varchar2(20 char),
    email           varchar2(50 char),
    status          varchar2(3 char) default 'N' not null enable,
    fehler_code     number(*, 0),
    fehler_text     varchar2(255 char),
    erstell_datum   date default sysdate not null enable,
    bearb_datum     date
);

alter table dirkspzm32.s_qs_babtec_adr_l
    add constraint pk_s_qs_babtec_adr_l primary key ( typ,
                                                      nummer )
        using index enable;


